namespace sv_067f73126e744e4b8ac9716b4534e977;

public class ApplicationState
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    // Track completed steps so the layout can highlight them
    public HashSet<int> CompletedSteps { get; } = [];

    public event Action? OnChange;

    public void NotifyChanged() => OnChange?.Invoke();
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <nav class="wizard-progress">
                @for (int i = 0; i < _steps.Length; i++)
                {
                    var step = _steps[i];
                    var stepNum = i + 1;
                    var cssClass = stepNum == _currentStep ? "active"
                        : stepNum < _currentStep ? "completed"
                        : "";
                    <a href="@step.Url" class="wizard-step @cssClass">
                        <span class="step-number">@stepNum</span>
                        <span class="step-label">@step.Label</span>
                    </a>
                }
            </nav>
            <span class="step-indicator">Step @_currentStep of @_steps.Length</span>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

@code {
    private readonly record struct StepInfo(string Url, string Label);

    private static readonly StepInfo[] _steps =
    [
        new("/apply/personal-info", "Personal Info"),
        new("/apply/experience", "Experience"),
        new("/apply/references", "References"),
        new("/apply/review", "Review"),
    ];

    private int _currentStep = 1;

    protected override void OnParametersSet()
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri).ToLowerInvariant();
        _currentStep = uri switch
        {
            "apply/experience" => 2,
            "apply/references" => 3,
            "apply/review" => 4,
            _ => 1,
        };
    }
}

.wizard-progress {
    display: flex;
    gap: 1rem;
    align-items: center;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 0.3rem;
    text-decoration: none;
    color: #666;
    font-size: 0.9rem;
}

.wizard-step .step-number {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.5rem;
    height: 1.5rem;
    border-radius: 50%;
    border: 2px solid #ccc;
    font-size: 0.75rem;
    font-weight: bold;
}

.wizard-step.active .step-number {
    background-color: #0d6efd;
    border-color: #0d6efd;
    color: white;
}

.wizard-step.completed .step-number {
    background-color: #198754;
    border-color: #198754;
    color: white;
}

.wizard-step.active .step-label {
    font-weight: bold;
    color: #0d6efd;
}

.wizard-step.completed .step-label {
    color: #198754;
}

.step-indicator {
    margin-left: auto;
    font-weight: bold;
    color: #333;
}

