@inherits LayoutComponentBase
@inject NavigationManager Nav

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            <nav class="wizard-progress">
                @for (int i = 0; i < _steps.Length; i++)
                {
                    var step = _steps[i];
                    var stepNum = i + 1;
                    var cssClass = stepNum == _currentStep ? "active"
                        : stepNum < _currentStep ? "completed"
                        : "";
                    <a href="@step.Url" class="wizard-step @cssClass">
                        <span class="step-number">@stepNum</span>
                        <span class="step-label">@step.Label</span>
                    </a>
                }
            </nav>
            <span class="step-indicator">Step @_currentStep of @_steps.Length</span>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

<div id="blazor-error-ui" data-nosnippet>
    An unhandled error has occurred.
    <a href="." class="reload">Reload</a>
    <span class="dismiss">🗙</span>
</div>

