    protected override void OnParametersSet()
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri).ToLowerInvariant();
        _currentStep = uri switch
        {
            "apply/experience" => 2,
            "apply/references" => 3,
            "apply/review" => 4,
            _ => 1,
        };
    }
}

