@page "/apply/personal-info"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="AppState.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input class="form-control" type="email" @bind="AppState.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void Next()
    {
        AppState.CompletedSteps.Add(1);
        AppState.NotifyChanged();
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Apply - Experience</PageTitle>

<h3>Work Experience</h3>

@for (int i = 0; i < AppState.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Job @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="AppState.JobHistory[index].Years" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddJob() => AppState.JobHistory.Add(new JobEntry());
    private void Remove(int index) => AppState.JobHistory.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        AppState.CompletedSteps.Add(2);
        AppState.NotifyChanged();
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState
@inject NavigationManager Nav

<PageTitle>Apply - References</PageTitle>

<h3>References</h3>

@for (int i = 0; i < AppState.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between">
            <strong>Reference @(index + 1)</strong>
            <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="AppState.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Email</label>
            <input class="form-control" type="email" @bind="AppState.References[index].Email" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="AppState.References[index].Relationship" />
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    private void AddReference() => AppState.References.Add(new ReferenceContact());
    private void Remove(int index) => AppState.References.RemoveAt(index);

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        AppState.CompletedSteps.Add(3);
        AppState.NotifyChanged();
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer
@inject ApplicationState AppState

<PageTitle>Apply - Review</PageTitle>

<h3>Review Your Application</h3>

<section class="mb-4">
    <h5>Personal Information</h5>
    <dl class="row">
        <dt class="col-sm-3">Name</dt>
        <dd class="col-sm-9">@AppState.Name</dd>
        <dt class="col-sm-3">Email</dt>
        <dd class="col-sm-9">@AppState.Email</dd>
    </dl>
</section>

<section class="mb-4">
    <h5>Work Experience</h5>
    @if (AppState.JobHistory.Count == 0)
    {
        <p class="text-muted">No jobs added.</p>
    }
    else
    {
        @foreach (var job in AppState.JobHistory)
        {
            <div class="card mb-2 p-2">
                <strong>@job.Title</strong> at @job.Company (@job.Years)
            </div>
        }
    }
</section>

<section class="mb-4">
    <h5>References</h5>
    @if (AppState.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    else
    {
        @foreach (var r in AppState.References)
        {
            <div class="card mb-2 p-2">
                <strong>@r.Name</strong> — @r.Email (@r.Relationship)
            </div>
        }
    }
</section>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    [Inject] private NavigationManager Nav { get; set; } = default!;

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        // TODO: Persist the application to a database
        Nav.NavigateTo("/");
    }
}

